INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098960e","title":"Стальной алхимик. Книга 8","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004681206/140/a913/Hiromu_Arakava__Stalnoj_alhimik._Kniga_8.jpg","isbn":"978-5-389-18088-8","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы. Манга","genres":["Комиксы","манга","графические романы"],"annotation":"Череда событий, выбранных решений и дорог опять ведёт братьев Эдварда и Альфонса Элриков к событиям того дня, когда их жизнь изменилась. Встреча с отцом. Новые факты о трансмутации дают ключ к возможности вернуть Алу тело. Шрам возвращается, и Мэй Чань присоединяется к нему. Эдвард примеряет на себя образ творца добрых дел. Нападение на Гогенгейма. Ловушка для Обжорства. Страшная тайна о фюрере. Из разрозненных элементов выплавляется философский камень истины…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-07","rating":5,"review":"","added":9999886,"hdCover":""},{"id":"098960d","title":"Стальной алхимик. Книга 7","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003964062/140/1353/Hiromu_Arakava__Stalnoj_alhimik._Kniga_7.jpg","isbn":"978-5-389-17731-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Легендарная серия манги показывает нам альтернативный 20-й век, в котором магия и алхимия идут в ногу с технологическим процессом. В центре сюжета два брата, Эдвард и Альфонс, попытка которых воскресить умершую мать с помощью алхимии приводит к ужасным последствиям…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-07","rating":5,"review":"","added":9999885,"hdCover":""},{"id":"098960c","title":"Стальной алхимик. Книга 6","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003595285/140/23ac/Hiromu_Arakava__Stalnoj_alhimik._Kniga_6.jpg","isbn":"978-5-389-17512-9","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Легендарная серия манги показывает нам альтернативный 20-й век, в котором магия и алхимия идут в ногу с технологическим процессом. В центре сюжета два брата, Эдвард и Альфонс, попытка которых воскресить умершую мать с помощью алхимии приводит к ужасным последствиям…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-07","rating":4.5,"review":"","added":9999884,"hdCover":""},{"id":"098960b","title":"Стальной алхимик. Книга 5","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003344927/140/c2b8/Hiromu_Arakava__Stalnoj_alhimik._Kniga_5.jpg","isbn":"978-5-389-17129-9","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Легендарная серия манги показывает нам альтернативный 20-й век, в котором магия и алхимия идут в ногу с технологическим процессом. В центре сюжета два брата, Эдвард и Альфонс, попытка которых воскресить умершую мать с помощью алхимии приводит к ужасным последствиям…  Перед нами пятый том захватывающей истории, в которой герои подбираются к загадке трансмутации человеческой души очень близко. Осталось только найти ключ к воспоминаниям одного из братьев Альфонса о том самом алхимическом эксперименте, который искалечил Эдварда и забрал тело Альфонса. Но на пути героев встают химеры и загадочный человек с татуировкой уробороса. Как будут развиваться события – читайте в пятом томе истории.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-07","rating":4.5,"review":"","added":9999883,"hdCover":""},{"id":"098960a","title":"Стальной алхимик. Книга 4","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003056419/140/5a9b/Hiromu_Arakava__Stalnoj_alhimik._Kniga_4.jpg","isbn":"978-5-389-16820-6","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Легендарная серия манги показывает нам альтернативный 20-й век, в котором магия и алхимия идут в ногу с технологическим процессом. В центре сюжета два брата, Эдвард и Альфонс, попытка которых спасти умершую мать с помощью алхимии приводит к ужасным последствиям. У Эдварда не остается иного выбора, как вступить в армию, чтобы попытаться найти способ восстановить искалеченное тело своего брата и свое собственное.  Четвертый том истории приоткрывает завесу прошлого братьев Элриков – мы знакомимся с их учителем госпожой Идзуми, вместе с героями разбираемся, что значит «одно – это всё, всё – это одно», переживаем первый и второй равноценные обмены, определяющие дальнейшую жизнь Эдварда и Альфонса, и восхищаемся стойкостью и целеустремленностью старшего брата. Эдвард Элрик становится Стальным Алхимиком, он талантлив и смел, хотя жизненного опыта ему, увы, пока не хватает…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-07","rating":4,"review":"","added":9999882,"hdCover":""},{"id":"0989609","title":"Стальной алхимик. Книга 3","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003013654/140/de44/Hiromu_Arakava__Stalnoj_alhimik._Kniga_3.jpg","isbn":"978-5-389-16022-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Бессменный участник всех топов лучших манга-серий, согласно мнению многих,манга номер 1 в мире.  Мировые продажи \"Стального Алхимика\" превышают 61 000 000 экземпляров!  Легендарная серия манги показывает нам альтернативный 20-й век, в котором магия и алхимия идут в ногу с технологическим процессом. В центре сюжета два брата, Эдвард и Альфонс, попытка которых спасти умершую мать с помощью алхимии приводит к ужасным последствиям. У Эдварда не остается иного выбора, как вступить в армию, чтобы попытаться найти способ восстановить искалеченное тело своего брата и свое собственное.  Манга выходит в шикарном полиграфическом оформлении делюкс издания, на мелованной бумаге в твердом переплете с суперобложкой! В нашем издании будут цветные страницы и скетчи, которые были и внутри оригинального издания, мы сохраним даже титульную страницу на кальке!  По мотивам манги \"Стальной Алхимик\" снято два аниме-сериала, представлено несколько видеоигр и игровой фильм!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Перечитал","read":"2022-07","rating":4.5,"review":"Предыдущее прочтение: Октябрь 2020, оценка 4.5","added":9999881,"hdCover":""}]');

