)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989607","title":"Стальной алхимик. Книга 1","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002946134/140/6b2e/Hiromu_Arakava__Stalnoj_alhimik._Kniga_1.jpg","isbn":"978-5-389-15939-6","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Легендарная серия манги показывает нам альтернативный 20-й век, в котором магия и алхимия идут в ногу с технологическим процессом. В центре сюжета два брата, Эдвард и Альфонс, попытка которых спасти умершую мать с помощью алхимии приводит к ужасным последствиям. У Эдварда не остается иного выбора, как вступить в армию, чтобы попытаться найти способ восстановить искалеченное тело своего брата и свое собственное.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Перечитал","read":"2022-07","rating":4.5,"review":"Предыдущее прочтение: Октябрь 2020, оценка 4.5","added":9999879,"hdCover":""},{"id":"0989606","title":"Последнее путешествие девочек. Том 3","author":"Цукумидзу","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005883363/140/e3cc/Tsukumidzu__Poslednee_puteshestvie_devochek._Tom_3.jpg","isbn":"978-5-17-132680-7","publisher":"АСТ, Mainstream","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Тито и Юри узнают от загадочных существ, что Земля вот-вот погибнет.  Но для девочек по-прежнему важно искать пропитание и топливо каждый день, чтобы прожить ещё один. Они продолжают своё путешествие и находят башню, которая достигает самого верхнего уровня.  Приближаясь к ней, Тито и Юри предаются воспоминаниям...  Что же ждёт девочек на самой вершине умирающего мира?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-07","rating":4.5,"review":"","added":9999878,"hdCover":""},{"id":"0989605","title":"Последнее путешествие девочек. Том 2","author":"Цукумидзу","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005569560/140/ab3c/Tsukumidzu__Poslednee_puteshestvie_devochek._Tom_2.jpg","isbn":"978-5-17-132682-1","publisher":"АСТ, Mainstream","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Тито и Юри продолжают своё путешествие по разрушенному миру. Они скитаются среди развалин, готовят еду в заброшенном пищевом комбинате, исследуют таинственные ряды чёрных плит, встречают роботов и заводят странноватого питомца…  Какие ещё открытия поджидают девочек на следующих уровнях?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-07","rating":4.5,"review":"","added":9999877,"hdCover":""},{"id":"0989604","title":"Последнее путешествие девочек. Том 1","author":"Цукумидзу","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005545773/140/8a9f/Tsukumidzu__Poslednee_puteshestvie_devochek._Tom_1.jpg","isbn":"978-5-17-132681-4","publisher":"АСТ, Реанимедиа","pubDate":"2020","language":"Русский","series":"Манга. Последнее путешествие девочек","genres":["Комиксы","манга","графические романы"],"annotation":"Постапокалипсис. Две девочки, Тито и Юри, остаются наедине с мёртвой цивилизацией.  Они путешествуют на своём любимом мотоцикле «Кеттенкраде» по руинам безжизненных городов в поисках еды и топлива. Серые и безнадёжные дни сменяют друг друга, но, пока девочки вместе, даже в самых мрачных моментах они находят что‑то светлое. А их чувства и переживания наполняют этот пустой мир моментами, ради которых всё‑таки ещё стоит жить...  Что же такое «обычная жизнь» для девочек, блуждающих среди руин? Эксцентричная манга от гениальной Цукумидзу исследует неизведанную область жанра повседневности.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-07","rating":4,"review":"","added":9999876,"hdCover":""},{"id":"0989603","title":"Чёрная вдова. Поцелуй или смерть (сборник)","author":"Марджери Лью","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005520981/140/6fed/Mardzheri_Lyu__Chjornaya_vdova._Potseluj_ili_smert_sbornik.jpg","isbn":"978-5-04-111780-1","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"Девушки Marvel","genres":["Комиксы","манга","графические романы"],"annotation":"Наташа Романова — убийца?! Будучи одним из величайших шпионов на планете, Наташа живёт в мире лжи и полуправды. Её товарищ по Мстителям и возлюбленный Капитан Америка даже не подозревает, сколько крови у неё на руках. Однако есть один секрет, который она хранит пуще остальных. И пока Наташа пытается сделать всё, чтобы его не раскрыли, кто-то соблазняет и убивает сенатора.  Сын убитого складывает вместе все улики, чтобы обнаружить, что ведут они к… Наташе Романовой! Также наша героиня получит шанс укрепить свою дружбу с Железным Человеком, помогая ему в противостоянии с сильным противником!  В сборник вошли выпуски комикса \"Чёрная Вдова\" (2010) #1–8, а также материалы из \"Добро пожаловать в эру героев\" #1 и \"Железный Человек: поцелуй или смерть\".","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-07","rating":3.5,"review":"","added":9999875,"hdCover":""},{"id":"0989602","title":"Черная вдова. Добро пожаловать в игру","author":"Ричард Морган","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004645749/140/7b7a/Richard_Morgan__Chernaya_vdova._Dobro_pozhalovat_v_igru.jpg","isbn":"978-5-04-111781-8","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Самая опасная шпионка вселенной Marvel наконец-то ушла на покой! Чёрной Вдове не так уж много и надо — просто дайте ей жить своей жизнью! Но реальность вторгается в быт героини: её пытаются убить! Вдова идёт по следу наёмников, раскрывая международный заговор, и возвращается в Россию, которую теперь и не узнать. Каким стал дом после стольких лет разлуки? Чёрная Вдова увидит это своими глазами.  Кто-то называет её шпионкой, кто-то — предательницей или ещё кем похуже, но в одном можно быть уверенным: дорогу Чёрной Вдове лучше не переходить! Последний, кто сделал это, поплатился жизнью, но его могущественные друзья хотят отомстить, так что теперь Наташа точно легко не отделается. И помочь ей не сможет даже сам Ник Фьюри.  Знаменитый писатель Ричард К. Морган (\"Видоизменный углерод\") создал невероятно напряженный шпионский триллер о Чёрной вдове, а легендарные художники Билл Сенкевич и Горан Парлов мастерски передали атмосферу смертельной игры опытных убийц, которым уже нечего терять. Забудьте о ярких костюмах, скандинавских богах и полётах между небоскрёбами: здесь работают профессионалы! Только холодный расчёт, политические интриги и неудержимое желание отомстить. Наташу Романову кто-то хочет убить, кто-то использовать в своих целях, а кто-то искренне желает помочь. Вот только сама Чёрная вдова планирует сорвать планы и врагов, и друзей, ведь она ведёт свою собственную игру!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-07","rating":4,"review":"","added":9999874,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989601","title":"Кэт. C.A.T. - Confidential Assassination Troop. Том 2","author":"Фун Йиньпан","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000452050/140/e289/Fun_Jinpan__Ket._C.A.T.__Confidential_Assassination_Troop._Tom_2.jpg","isbn":"978-5-9901457-2-6,  978-5-9901457-3-3,  978-986-11-8884-3","publisher":"Истари Комикс","pubDate":"2008","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Специальный агент «CAT», с детства обученная убивать людей, была тяжело ранена при столкновении с русским отрядом «BEAR». К счастью, ее спас молодой художник. На время лечения она оставила ремесло наемного убийцы и стала вести обычную жизнь.  Но только Кэт вновь почувствовала себя человеком, как снова оказалась втянута в конфликт, который может погубить мир!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-07","rating":4,"review":"","added":9999873,"hdCover":""},{"id":"0989600","title":"Кэт. Том 1","author":"Фун Йиньпан","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000315346/140/b139/Fun_Jinpan__Ket._Tom_1.jpg","isbn":"978-5-9901457-1-9","publisher":"Истари Комикс","pubDate":"2008","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Ближайшее будущее. Информационное противостояние крупнейших государств - подготовка к третьей мировой войне, которую все ожидают. Первостепенной задачей становится захват информации и технологий противника, и главные орудия в этом деле - агенты спецслужб и наёмники. Это российское подразделение «BEAR», китайские «Драконы» и… американские отряды ликвидации «Confidential Assassination Troop», сокращенно называемые C.A.T. И теперь им предстоит столкнуться друг с другом!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-07","rating":4,"review":"","added":9999872,"hdCover":""},{"id":"09895ff","title":"Черная вдова. Графический роман","author":"Грег Рака,Девин Грейсон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004664205/140/3c4e/__Chernaya_vdova._Graficheskij_roman.jpg","isbn":"978-5-04-111719-1","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"Война вдов! Наташа Романова всегда вела жизнь, полную приключений. Бывшая советская шпионка, она переметнулась на сторону Запада и стала супергероиней и Мстителем. У Наташи репутация непревзойдённого профессионала: уравновешенного, рационального и смертельно опасного, как паук, что дал ей имя. Но сейчас, возможно, её время в качестве Чёрной Вдовы подходит к концу!  Елена Белова — первая ученица в истории Красной Комнаты, превзошедшая Наташу, и теперь она жаждет славы, которую, по её мнению, у неё украли. И она намерена вырыть для соперницы могилу! Готовьтесь к бою посреди пустынь Среднего Востока и Верхнего Вест-Сайда в Нью-Йорке. А также узнайте историю \"бледного паучка\" в рассказе о московских приключениях Беловой! Не одна, а целых две Чёрных вдовы! Не одна, а целых три истории под одной обложкой! И это не просто рассказы о бездумной раздаче тумаков, а самые настоящие шпионские и детективные истории! Сначала Романова и Белова схлестнутся в схватке на новое биологическое оружие, затем одна украдёт жизнь другой, а в конце вас ждут приключения Чёрной вдовы на самом дне Москвы, где ей придётся искать убийцу своего наставника вместе с работниками МУР. Отдельно стоит обратить внимание на рисунок, за каждую историю отвечает свой художник, очень разные, но отлично справляющиеся с задачей передать темп и настроение повестования!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":4.5,"review":"","added":9999871,"hdCover":""},{"id":"09895fe","title":"Мстители #43. Первое появление Красногвардейца","author":"Стэн Ли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006292854/140/2eff/Sten_Li__Mstiteli_43._Pervoe_poyavlenie_Krasnogvardejtsa.jpg","isbn":"978-5-04-114275-9","publisher":"Комильфо","pubDate":"2021","language":"","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В грядущем блокбастере Marvel Studios «Чёрная Вдова» роль Красногвардейца исполнит Дэвид Харбор, полюбившийся зрителям по роли полицейского Джима Хоппера в сериале «Очень странные дела», и это будет первым появлением советского аналога суперсолдата на киноэкране. А каким же оно было в комиксах? О, ну тут всё гораздо интереснее, чем в кино! В этом выпуске вас ждёт схватка Красногвардейца с Мстители, среди которых присутствует настоящий греческий бог! И чтобы отвлечь его, злобные коммунисты призывают многоголовую гидру! Как им это удалось? Узнаете, открыв журнал, который можно без сомнений назвать образцом классических супергеройских комиксов!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":4,"review":"","added":9999870,"hdCover":""},{"id":"09895fd","title":"Тревожные истории #57. Первое появление Хоукая","author":"Стэн Ли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003752436/140/f735/Sten_Li__Trevozhnye_istorii_57._Pervoe_poyavlenie_Houkaya.jpg","isbn":"9785041094584","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Классика Marvel","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":4,"review":"","added":9999869,"hdCover":""},{"id":"09895fc","title":"Тревожные истории #52. Первое появление Чёрной Вдовы","author":"Стэн Ли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007117884/140/1dbf/Sten_Li__Trevozhnye_istorii_52._Pervoe_poyavlenie_Chjornoj_Vdovy.jpg","isbn":"978-5-04-114179-0","publisher":"Комильфо","pubDate":"2021","language":"","series":"Классика Marvel","genres":["Комиксы","манга","графические романы"],"annotation":"Совсем скоро все поклонники комиксов наконец-то смогут насладиться сольным фильмом про обворожительную советскую шпионку, а значит пришло время лицезреть и её первое появление в комиксах! Чёрная Вдова и невероятный украинский учёный и сила Борис получают задание проникнуть в США и разрушить изнутри оружейный концерн Тони Старка и вернуть на родину профессора Ванко, предавшего свою страну. И пока Наташа Романова занимается обольщением самого гения, плейбоя и филантропа, Борис вступит в смертельный бой с телохранителем Старка, Железным Человеком! Также вас ждут несколько коротких историй, которые входили в оригинальный журнал. Они отлично помогут вам почувствовать дух эпохи классических комиксов!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":4,"review":"","added":9999868,"hdCover":""},{"id":"09895fb","title":"Кей","author":"Дзиро Танигути,Сиро Тосаки","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007035747/140/f029/__Kej.jpg","isbn":"978-5-7584-0629-8","publisher":"Фабрика комиксов","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Говорят, с высоты горных вершин Кей видит то, что таится в человеческих сердцах. Он ходит рядом с богами… Там, в вышине, звучат совершенно другие голоса — не те, что привычны людям… Они перекликаются эхом в горах и разлетаются по всему миру, становясь законом и волей Божьей!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":4,"review":"","added":9999867,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09895fa","title":"Атака на титанов. Книга 17","author":"Хадзимэ Исаяма","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006264579/140/fca5/Hadzime_Isayama__Ataka_na_titanov._Kniga_17.jpg","isbn":"978-5-389-19944-6","publisher":"Азбука, Азбука-Аттикус","pubDate":"2021","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Покинувшие Парадиз титаны, ведомые Эреном Йегером, уничтожают все живое на своем пути. Микаса, Армин и остальные плывут в Одиху в надежде подготовить самолет, чтобы нагнать изначального титана и его армию по воздуху. Близится последний бой. Смогут ли эльдийцы и их соратники остановить Эрена и спасти человечество? Или же всему миру настанет конец?..","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":5,"review":"","added":9999866,"hdCover":""},{"id":"09895f9","title":"Attack on Titan: Volume 34","author":"Хадзимэ Исаяма","type":"Манга","cover":"https://s1.livelib.ru/boocover/1006726393/140/487d/Hadzime_Isayama__Attack_on_Titan_Volume_34.jpg","isbn":"978-1-64651-236-2","publisher":"Kodansha Comics","pubDate":"2021","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"Eren’s titanic Rumbling claims thousands of lives beyond the walls of Paradis, and the boy who once lived in fear of the Titans becomes the world’s most feared man. Determined to stop the destruction wrought by their childhood friend, Armin, Mikasa, and their surviving comrades reach the Attack Titan and decide to face him head on in an ultimate showdown. Will humanity finally be set free from the cycle of fear, oppression, and destruction, or will the Titans outlive their victims?  FINAL VOLUME!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":5,"review":"","added":9999865,"hdCover":""},{"id":"09895f8","title":"Attack on Titan: Volume 32","author":"Хадзимэ Исаяма","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005059677/140/41b9/Hadzime_Isayama__Attack_on_Titan_Volume_32.jpg","isbn":"9781646510313","publisher":"Kodansha Comics","pubDate":"2020","language":"","series":"Attack on Titan","genres":["Боевое фэнтези","Зарубежное фэнтези"],"annotation":"Determined to protect his beloved home of Paradis, Eren uses the Founding Titan’s power in an attempt to wipe out the rest of humanity. As the droves of Titans press on, Eren, long unrecognizable as a friend, a brother, a savior, has become indiscernible from a devil… Now, Mikasa, Armin, and the surviving members of the Survey Corps must band together with their sworn enemies–Marleyan soldiers and 104th defectors–to save the world.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":5,"review":"","added":9999864,"hdCover":""},{"id":"09895f7","title":"Еретик","author":"Кларк Эштон Смит,Алексей Горбут,Харальд Бьёрнсон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003533259/140/cd89/__Eretik.jpg","isbn":"978-5-99093-626-3","publisher":"КомФедерация","pubDate":"2019","language":"Русский","series":"Отечественные комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"Легенда гласит, что где-то во мраке подземелий заброшенного замка, таятся несметные богатства проклятой царицы Эрекшигаль. Но, чтобы отыскать их, придётся рискнуть всем, даже своей душой! Некромантия - опасный вид магии, и, если ты выбираешь его, то будь готов общаться с малоприятными подгнившими личностями, тогда как красивые и вежливые будут желать твоей смерти. Отринь сомнения и страх и завоюй расположение Верховного Лича, иначе Инвокация Неудачи неизбежно настигнет. Твой путь будет пролегать через истерзанную войнами страну Муринию, армию которой возглавляют хладнокровные кровопийцы. И их армия не желает отставать от технического прогресса. Тебе интересно узнать, сколько вампиров нужно для того, чтобы починить танк…танк вампиров? В течение столетий укутанные в холодный туман северные пустоши и кишащие насекомыми топи юга рождали на свет одиноких варваров. Но лишь одному из них судьба уготовила стать чем-то большим. Он - Гремгр-Истязатель. Он убивает без жалости. Он никого не любит. А очередной квест, в чёрных осклизлых кавернах, населенных гоблинами и тенями прошлого, ты пройдешь вместе с ним.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":4,"review":"","added":9999863,"hdCover":""},{"id":"09895f6","title":"Attack on Titan: Volume 31","author":"Хадзимэ Исаяма","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003965826/140/4841/Hadzime_Isayama__Attack_on_Titan_Volume_31.jpg","isbn":"9781632369796","publisher":"Kodansha Comics","pubDate":"2020","language":"","series":"Attack on Titan","genres":["Боевое фэнтези","Зарубежное фэнтези"],"annotation":"After breaking through a stronghold of old friends and enemies, Zeke hands down his plan for the Eldians to Eren. But what Eren was plotting with his rumbling powers leaves his brother in the dust, betrayed and alone once more. Now, with some help from Ymir, a parade of massive Titans are roused from their centuries-long slumber, breaking free of the Walls to answer their founder’s call. Where the march leads, only Eren knows…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":5,"review":"","added":9999862,"hdCover":""},{"id":"09895f5","title":"Attack on Titan: Volume 30","author":"Хадзимэ Исаяма","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003612280/140/3a63/Hadzime_Isayama__Attack_on_Titan_Volume_30.jpg","isbn":"9781632369024","publisher":"Kodansha Comics","pubDate":"2020","language":"Английский","series":"Attack on Titan","genres":["Боевое фэнтези","Зарубежное фэнтези"],"annotation":"To activate the true power of the Founding Titan that courses through his veins, Eren must make contact with Zeke, a Titan of royal blood. Though Zeke has escaped Levi and the Survey Corps, he''s made little headway before the Marleyan military and its Titan warriors attack. Eren pummels his way through the Marleyan trap and past his former friends, but as the battle rages, he stumbles into a situation far beyond what his brother could have planned.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":5,"review":"","added":9999861,"hdCover":""},{"id":"09895f4","title":"Attack on Titan: Volume 29","author":"Хадзимэ Исаяма","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003050729/140/3411/Hadzime_Isayama__Attack_on_Titan_Volume_29.jpg","isbn":"978-1632368287","publisher":"Kodansha Comics","pubDate":"2019","language":"Английский","series":"Attack on Titan","genres":["Боевое фэнтези","Зарубежное фэнтези"],"annotation":"WITHIN THE HOLLOW CROWN  As a Marleyan invasion dangles like a guillotine blade over the island of Paradis, allies have become enemies, and former friends are at each other''s throats. The Yeagerists are in all-out revolt, fighting to dismantle military rule before the potential for world war explodes into certain doom. Meanwhile, deep in the forest, the sides'' most ruthless, fanatical killers are locked in single combat, but triumph is elusive where Titans are involved...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":5,"review":"","added":9999860,"hdCover":""},{"id":"09895f3","title":"Attack on Titan: Volume 28","author":"Хадзимэ Исаяма","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002979100/140/d8db/Hadzime_Isayama__Attack_on_Titan_Volume_28.jpg","isbn":"978-1632367839","publisher":"Kodansha Comics","pubDate":"2019","language":"Английский","series":"Attack on Titan","genres":["Боевое фэнтези","Зарубежное фэнтези"],"annotation":"RUTHLESS SAVIOR  After years as a lonely double agent, Zeke finally returns to the good graces of his home island of Paradis. Still, the Survey Corps refuses to let him meet Eren--the other ingredient in the earth-shaking weapon-- for fear the explosive duo will be impossible to control. Meanwhile, the public responds badly to the military''s open distrust of their hero Eren, and the detention of the Marleyan volunteers spurs an uprising. Amid the turmoil, Eren takes matters into his own hands...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":5,"review":"","added":9999859,"hdCover":""},{"id":"09895f2","title":"Attack on Titan: Volume 27","author":"Хадзимэ Исаяма","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002911793/140/d804/Hadzime_Isayama__Attack_on_Titan_Volume_27.jpg","isbn":"978-1632367174","publisher":"Kodansha Comics","pubDate":"2019","language":"","series":"Attack on Titan","genres":["Боевое фэнтези","Зарубежное фэнтези"],"annotation":"MINUTES TO MIDNIGHT  Eren has infiltrated Marley territory and dealt the empire a devastating blow. But the real goal of the mission was always to get Zeke back to Paradis Island in secrecy. Now that this Titan heir of royal blood is inside the Walls, the island''s military government has its \"earth-rumbling\" weapon of mass destruction. But has this supposed deterrent actually started a countdown to total world war?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":5,"review":"","added":9999858,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09895f1","title":"Attack on Titan: Volume 26","author":"Hajime Isayama","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002833683/140/9c0e/Hajime_Isayama__Attack_on_Titan_Volume_26.jpg","isbn":"978-1632366542","publisher":"Kodansha Comics","pubDate":"2018","language":"Английский","series":"Attack on Titan","genres":["Боевое фэнтези","Зарубежное фэнтези"],"annotation":"CLASH OF THE ELDIANS  The deadly pageant directed by and starring Willy Tybur clearly illustrates the threat posed by the island of Paradis, as the dangerous rebel Eren Yeager mows down civilians and deals a massive blow to the Marleyan army. Meanwhile, the Eldian soldiers including Mikasa, Connie, and Sasha sow chaos in the city and disrupt military communications. But the battle between Eren and the War Hammer Titan isn''t over, and it''s about to draw in the full might of this land''s warriors...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":5,"review":"","added":9999857,"hdCover":""},{"id":"09895f0","title":"Attack on Titan: Volume 25","author":"Hajime Isayama","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002773619/140/3a4c/Hajime_Isayama__Attack_on_Titan_Volume_25.jpg","isbn":"978-1632366139","publisher":"Kodansha Comics","pubDate":"2018","language":"Английский","series":"Attack on Titan","genres":["Боевое фэнтези","Зарубежное фэнтези"],"annotation":"The final battle rages on between the Survey Corps and the genocidal Colossus and Armored Titans. It''s a personal fight that has driven old friends to kill each other, with the fate of humanity and the truth behind the Titan threat in the balance!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-06","rating":5,"review":"","added":9999856,"hdCover":""},{"id":"09895ef","title":"Электра. Том 2. Реверанс","author":"Хейден Блэкман","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002803139/140/52cb/Hejden_Blekman__Elektra._Tom_2._Reverans.jpg","isbn":"978-5-91339-656-3","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-05","rating":3,"review":"","added":9999855,"hdCover":""},{"id":"09895ee","title":"Электра. Том 1. Кровные узы","author":"Хейден Блэкман,Майкл Дель Мундо","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002087590/140/cce0/__Elektra._Tom_1._Krovnye_uzy.jpg","isbn":"978-5-91339-472-9","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Электра готовится пролить свет на своё прошлое и изменить будущее. В поисках неуловимого наёмника по прозвищу Капский Ворон она бросает вызов всем опасностям Острова Чудовищ — в том числе и маньяку по кличке Кровавые Губы! Но цель Электры — не то, чем кажется, возможно, она ещё не готова для этого путешествия. Сможет ли самая опасная роковая женщина Marvel одолеть Капского Ворона и получить самую крупную награду в её карьере? Легендарные убийцы сталкиваются лицом к лицу на краю света, а сама Электра оказывается на волосок от смерти.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-05","rating":3.5,"review":"","added":9999854,"hdCover":""}]');
